#include <climits>\n#include <cstdint>\n#include <iostream>\n#include <queue>\n#include <stack>\n#include <vector>\n\n#define INF UINT64_MAX\n\nclass Graph {\n public:\n  Graph(size_t n, const std::vector<std::pair<size_t, size_t>>& edges) {\n    table_.resize(n);\n    Build(edges);\n  }\n\n  std::stack<size_t> FindPath(size_t a, size_t b) {\n    auto n = table_.size();\n    a--;\n    b--;\n    std::vector<size_t> dist(n, INF);\n    std::stack<size_t> path;\n    std::vector<size_t> prev(n, -1);\n    dist[a] = 0;\n    std::queue<size_t> queue;\n    queue.push(a);\n    while (!queue.empty()) {\n      auto runner = queue.front();\n      queue.pop();\n      const std::vector<size_t>& children = table_[runner];\n      for (auto child : children) {\n        if (dist[child] != INF) {\n          continue;\n        }\n        prev[child] = runner;\n        queue.push(child);\n        dist[child] = dist[runner] + 1;\n      }\n      if (dist[b] != INF) {\n        break;\n      }\n    }\n    if (dist[b] != INF) {\n      auto runner = b;\n      for (; a != runner; runner = prev[runner]) {\n        path.push(runner + 1);\n      }\n      path.push(runner + 1);\n    }\n    return path;\n  }\n\n private:\n  void Build(const std::vector<std::pair<size_t, size_t>>& edges) {\n    for (const std::pair<size_t, size_t>& pair : edges) {\n      auto a = pair.first - 1;\n      auto b = pair.second - 1;\n      table_[a].push_back(b);\n      table_[b].push_back(a);\n    }\n  }\n\n  std::vector<std::vector<size_t>> table_;\n};\n\nint main() {\n  size_t n = 0;\n  size_t m = 0;\n  size_t a = 0;\n  size_t b = 0;\n  std::cin >> n >> m >> a >> b;\n\n  std::vector<std::pair<size_t, size_t>> edges(m);\n  for (size_t it = 0; it < m; it++) {\n    std::cin >> edges[it].first >> edges[it].second;\n  }\n\n  Graph g(n, edges);\n\n  std::stack<size_t> path = g.FindPath(a, b);\n  if (path.empty()) {\n    std::cout << -1 << std::endl;\n    return 0;\n  }\n  std::cout << path.size() - 1 << std::endl;\n  for (; !path.empty(); path.pop()) {\n    std::cout << path.top() << ' ';\n  }\n  std::cout << std::endl;\n  return 0;\n}\n